from flask import Flask, request, jsonify
import redis

app = Flask(__name__)

# Redis connection settings
redis_config = {
    'host': 'localhost',
    'port': 6379,
    'db': 0
}

# Create a Redis client instance
r = redis.Redis(**redis_config)

@app.route('/execute', methods=['POST'])
def execute_redis_command():
    if request.method == 'POST':
        command = request.args.get('command')
        
        # Prevent datastore security by whitelisting allowed commands
        allowed_commands = ['FLUSHDB', 'FLUSHALL', 'DEL', 'EXPIRE', 'TTL']
        if command in allowed_commands:
            try:
                result = r.execute_command(command)
                return jsonify({'result': result})
            except Exception as e:
                return jsonify({'error': str(e)})
        else:
            return jsonify({'error': 'Unauthorized Redis command'}), 401

if __name__ == '__main__':
    app.run(debug=True)